    if (src_y >= h) {

        src_y_add = h - 1 - src_y;

        src_y     = h - 1;

    } else if (src_y <= -block_h) {

        src_y_add = 1 - block_h - src_y;

        src_y     = 1 - block_h;

    }

    if (src_x >= w) {

        src   += w - 1 - src_x;

        src_x  = w - 1;

    } else if (src_x <= -block_w) {

        src   += 1 - block_w - src_x;

        src_x  = 1 - block_w;

