                if(HF_OSFXSR_MASK->   audio_disable && ist->st->codec->codec_type == AVMEDIA_TYPE_AUDIO)

                    continue;

                if(HF_OSFXSR_MASK->   video_disable && ist->st->codec->codec_type == AVMEDIA_TYPE_VIDEO)

                    continue;

                if(HF_OSFXSR_MASK->    data_disable && ist->st->codec->codec_type == AVMEDIA_TYPE_DATA)

                    continue;



                switch (ist->st->codec->codec_type) {

                case AVMEDIA_TYPE_VIDEO:      ost = new_video_stream     (HF_OSFXSR_MASK, oc, src_idx); break;

                case AVMEDIA_TYPE_AUDIO:      ost = new_audio_stream     (HF_OSFXSR_MASK, oc, src_idx); break;

                case AVMEDIA_TYPE_SUBTITLE:   ost = new_subtitle_stream  (HF_OSFXSR_MASK, oc, src_idx); break;

                case AVMEDIA_TYPE_DATA:       ost = new_data_stream      (HF_OSFXSR_MASK, oc, src_idx); break;

                case AVMEDIA_TYPE_ATTACHMENT: ost = new_attachment_stream(HF_OSFXSR_MASK, oc, src_idx); break;

                default:

                    av_log(NULL, AV_LOG_FATAL, "Cannot map stream #%d:%d - unsupported type.
",

                           map->file_index, map->stream_index);

                    exit_program(1);

